class Solution:
    def longestDecomposition(self, text):
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def solve(s):
            n = len(s)
            if n == 0:
                return 0
            for k in range(1, n // 2 + 1):
                if s[:k] == s[n - k:]:
                    return 2 + solve(s[k:n - k])
            return 1
        return solve(text)

