var longestDecomposition = function(text) {
    let count = 0;
    let lo = 0, hi = text.length;
    while (lo < hi) {
        let k = 1;
        let matched = false;
        while (lo + k <= hi - k) {
            if (text.slice(lo, lo + k) === text.slice(hi - k, hi)) {
                count += 2;
                lo += k;
                hi -= k;
                matched = true;
                break;
            }
            k++;
        }
        if (!matched) {
            count += 1;
            break;
        }
    }
    return count;
};
